17	}
18	
19	interface Customer {
20	  yearsWithMHPCO: number;
21	  quoteNumber?: number;
22	}
23	
24	interface Scenario {
25	  customer: Customer;
26	  steps: Step[];
27	}
28	
29	const PROCESSING_FEE = 5;
30	const FIRST_INSURANCE_RATE = 0.1;
31	
32	const BASE_PREMIUM: Record<string, number> = {
33	  sword: 100,
34	  amulet: 60,
35	  staff: 80,
36	  potion: 40,
37	  rune: 25,
38	  moonstone: 25,
39	};
40	
41	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
42	const BLOCK_SIZE = 3;
43	const BLOCK_PREMIUM = 60;
44	const CURSE_SURCHARGE_RATE = 0.5;
45	const HIGH_ENCHANTMENT_THRESHOLD = 5;
46	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
47	const LOYALTY_THRESHOLD_YEARS = 2;
48	const LOYALTY_DISCOUNT_RATE = 0.2;
49	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
50	const DEDUCTIBLE = 100;
51	const INSURANCE_CAP_MULTIPLIER = 2;
52	
53	const INSURANCE_VALUE: Record<string, number> = {
54	  sword: 1000,
55	  rune: 250,
56	};
57	
58	function calculateBasePremium(items: Item[]): number {
59	  const typeCounts: Record<string, number> = {};
60	  for (const item of items) {
61	    typeCounts[item.type] = (typeCounts[item.type] || 0) + 1;
62	  }
63	
64	  return Object.entries(typeCounts).reduce((total, [type, count]) => {
65	    const premium = COMPONENT_TYPES.has(type) && count === BLOCK_SIZE
66	      ? BLOCK_PREMIUM
67	      : count * BASE_PREMIUM[type];
68	    return total + premium;
69	  }, 0);
70	}
71	
72	function calculateLoyaltyDiscount(customer: Customer, basePremium: number): number {
73	  return customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
74	    ? basePremium * LOYALTY_DISCOUNT_RATE
75	    : 0;
76	}
77	
78	function calculateFollowUpDiscount(customer: Customer, basePremium: number): number {
79	  return (customer.quoteNumber ?? 1) >= 2
80	    ? basePremium * FOLLOW_UP_DISCOUNT_RATE
81	    : 0;
82	}
83	
84	function calculateItemSurcharges(items: Item[]): number {
85	  return items.reduce((total, item) => {
86	    const itemBasePremium = BASE_PREMIUM[item.type];
87	    const curseSurcharge = item.cursed ? itemBasePremium * CURSE_SURCHARGE_RATE : 0;
88	    const enchantmentSurcharge = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
89	      ? itemBasePremium * HIGH_ENCHANTMENT_SURCHARGE_RATE
90	      : 0;
91	    return total + curseSurcharge + enchantmentSurcharge;
92	  }, 0);
93	}
94	
95	function calculateInsuranceCap(policyItems: Item[]): number {
96	  const insuranceSum = policyItems.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
97	  return insuranceSum * INSURANCE_CAP_MULTIPLIER;
98	}
99	
100	function calculateClaimPayout(damages: Damage[]): number {
101	  return damages.reduce((sum, damage) => sum + Math.max(damage.amount - DEDUCTIBLE, 0), 0);
102	}
103	
104	export function processScenario(scenario: Scenario): unknown[] {
105	  const results: unknown[] = [];
106	
107	  for (const step of scenario.steps) {
108	    if (step.type === "quote") {
109	      const items = step.items!;
110	      const basePremium = calculateBasePremium(items);
111	      const itemSurcharges = calculateItemSurcharges(items);
112	      const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
113	      const loyaltyDiscount = calculateLoyaltyDiscount(scenario.customer, basePremium);
114	      const followUpDiscount = calculateFollowUpDiscount(scenario.customer, basePremium);
115	      const premium = Math.ceil(basePremium + itemSurcharges + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
116	      results.push({ premium });
117	    } else if (step.type === "claim") {
118	      const policyItems = scenario.steps[step.policy!].items!;
119	      const cap = calculateInsuranceCap(policyItems);
120	      const totalPayout = calculateClaimPayout(step.damages!);
121	      const payout = Math.min(totalPayout, cap);
122	      const remainingCap = cap - payout;
123	      results.push({ payout, remainingCap });
124	    }
125	  }
126	
127	  return results;
128	}
