42	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
43	const BLOCK_SIZE = 3;
44	const BLOCK_PREMIUM = 60;
45	const CURSE_SURCHARGE_RATE = 0.5;
46	const HIGH_ENCHANTMENT_THRESHOLD = 5;
47	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
48	const LOYALTY_THRESHOLD_YEARS = 2;
49	const LOYALTY_DISCOUNT_RATE = 0.2;
50	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
51	const DEDUCTIBLE = 100;
52	const CLAIM_HIGH_ENCHANTMENT_THRESHOLD = 8;
53	const CLAIM_HALF_REIMBURSEMENT_RATE = 0.5;
54	const INSURANCE_CAP_MULTIPLIER = 2;
55	
56	const INSURANCE_VALUE: Record<string, number> = {
57	  sword: 1000,
58	  rune: 250,
59	};
60	
61	function calculateBasePremium(items: Item[]): number {
62	  const typeCounts: Record<string, number> = {};
63	  for (const item of items) {
64	    typeCounts[item.type] = (typeCounts[item.type] || 0) + 1;
65	  }
66	
67	  return Object.entries(typeCounts).reduce((total, [type, count]) => {
68	    const premium = COMPONENT_TYPES.has(type) && count === BLOCK_SIZE
69	      ? BLOCK_PREMIUM
70	      : count * BASE_PREMIUM[type];
71	    return total + premium;
72	  }, 0);
73	}
