75	function calculateLoyaltyDiscount(customer: Customer, basePremium: number): number {
76	  return customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
77	    ? basePremium * LOYALTY_DISCOUNT_RATE
78	    : 0;
79	}
80	
81	function calculateFollowUpDiscount(customer: Customer, basePremium: number): number {
82	  return (customer.quoteNumber ?? 1) >= 2
83	    ? basePremium * FOLLOW_UP_DISCOUNT_RATE
84	    : 0;
85	}
