87	function calculateItemSurcharges(items: Item[]): number {
88	  return items.reduce((total, item) => {
89	    const itemBasePremium = BASE_PREMIUM[item.type];
90	    const curseSurcharge = item.cursed ? itemBasePremium * CURSE_SURCHARGE_RATE : 0;
91	    const enchantmentSurcharge = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
92	      ? itemBasePremium * HIGH_ENCHANTMENT_SURCHARGE_RATE
93	      : 0;
94	    return total + curseSurcharge + enchantmentSurcharge;
95	  }, 0);
96	}
