98	function calculateInsuranceCap(policyItems: Item[]): number {
99	  const insuranceSum = policyItems.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
100	  return insuranceSum * INSURANCE_CAP_MULTIPLIER;
101	}
