112	export function processScenario(scenario: Scenario): unknown[] {
113	  const results: unknown[] = [];
114	
115	  for (const step of scenario.steps) {
116	    if (step.type === "quote") {
117	      const items = step.items!;
118	      const basePremium = calculateBasePremium(items);
119	      const itemSurcharges = calculateItemSurcharges(items);
120	      const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
121	      const loyaltyDiscount = calculateLoyaltyDiscount(scenario.customer, basePremium);
122	      const followUpDiscount = calculateFollowUpDiscount(scenario.customer, basePremium);
123	      const premium = Math.ceil(basePremium + itemSurcharges + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
124	      results.push({ premium });
125	    } else if (step.type === "claim") {
126	      const policyItems = scenario.steps[step.policy!].items!;
127	      const cap = calculateInsuranceCap(policyItems);
128	      const totalPayout = calculateClaimPayout(step.damages!, policyItems);
129	      const payout = Math.min(totalPayout, cap);
130	      const remainingCap = cap - payout;
131	      results.push({ payout, remainingCap });
132	    }
133	  }
134	
135	  return results;
136	}
